Here are comprehensive pytest-style unit tests for the `is_palindrome` function:

```python
import pytest
from solution import is_palindrome


# ---------------------------------------------------------------------------
# Happy path – strings that ARE palindromes
# ---------------------------------------------------------------------------

class TestIsPalindromeTrue:
    def test_simple_word(self):
        assert is_palindrome("racecar") is True

    def test_single_character(self):
        assert is_palindrome("a") is True

    def test_two_same_characters(self):
        assert is_palindrome("aa") is True

    def test_mixed_case(self):
        assert is_palindrome("RaceCar") is True

    def test_all_uppercase(self):
        assert is_palindrome("MADAM") is True

    def test_phrase_with_spaces(self):
        assert is_palindrome("never odd or even") is True

    def test_phrase_with_mixed_case_and_spaces(self):
        assert is_palindrome("A man a plan a canal Panama".replace(" ", "")) is True

    def test_single_space_treated_as_empty(self):
        # A single space becomes "" after stripping, which is a palindrome
        assert is_palindrome(" ") is True

    def test_empty_string(self):
        assert is_palindrome("") is True

    def test_two_spaces(self):
        # Two spaces become "" after stripping
        assert is_palindrome("  ") is True

    def test_palindrome_with_numbers(self):
        assert is_palindrome("12321") is True

    def test_palindrome_with_special_characters(self):
        # Special characters are NOT stripped, so they must mirror
        assert is_palindrome("!aba!") is True


# ---------------------------------------------------------------------------
# Happy path – strings that are NOT palindromes
# ---------------------------------------------------------------------------

class TestIsPalindromeFalse:
    def test_simple_non_palindrome(self):
        assert is_palindrome("hello") is False

    def test_two_different_characters(self):
        assert is_palindrome("ab") is False

    def test_almost_palindrome(self):
        assert is_palindrome("racecars") is False

    def test_reversed_word(self):
        assert is_palindrome("abcd") is False

    def test_non_palindrome_with_spaces(self):
        assert is_palindrome("not a palindrome") is False

    def test_non_palindrome_numbers(self):
        assert is_palindrome("12345") is False


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------

class TestEdgeCases:
    def test_empty_string_is_palindrome(self):
        assert is_palindrome("") is True

    def test_whitespace_only_is_palindrome(self):
        # All spaces are removed → empty string → palindrome
        assert is_palindrome("   ") is True

    def test_case_insensitivity(self):
        assert is_palindrome("Aba") is True
        assert is_palindrome("ABA") is True
        assert is_palindrome("aBa") is True

    def test_spaces_are_ignored(self):
        # "a b a" → "aba" → palindrome
        assert is_palindrome("a b a") is True

    def test_spaces_ignored_non_palindrome(self):
        # "a b c" → "abc" → not a palindrome
        assert is_palindrome("a b c") is False

    def test_special_characters_not_stripped(self):
        # "!abc!" → palindrome; "!abc" → not a palindrome
        assert is_palindrome("!abc!") is False  # "!abc!" reversed is "!cba!"
        assert is_palindrome("!a!") is True

    def test_numeric_string_palindrome(self):
        assert is_palindrome("0") is True
        assert is_palindrome("1001") is True

    def test_numeric_string_non_palindrome(self):
        assert is_palindrome("10") is False
